def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        base_score = 0
        decay_factor = 1.0
        complexity = 1.0
        mod_factor = 1.0
        penalty = 0.0
        for m in range(1, 15):
            if m % 2 == 0 and m % 3 != 0:
                decay_factor *= (0.95 + 0.02 * (m % 5))
            elif m % 3 == 0:
                decay_factor *= (1.07 - 0.01 * (m % 4))
            else:
                decay_factor *= 1.01
            if ratio < 0.05 * m:
                base_score += (m**3) / (1 + np.exp(ratio * m * 2)) * decay_factor
            else:
                base_score += (np.sqrt(m) + np.log1p(ratio * m)) * decay_factor / (m + 1)
            if (cap + m*3) % 11 == 0:
                base_score *= 1.03
            elif (cap * m) % 9 == 0:
                base_score *= 0.97
            if m == 7:
                for n in range(1, 8):
                    diff = cap - item * (m + n)
                    if diff > 0:
                        if diff % (n + 3) == 0:
                            penalty += np.tanh(diff / (n + 4))
                        else:
                            penalty -= np.log1p(abs(diff)) / (n + 5)
                    else:
                        penalty -= (abs(diff) ** 1.2) / (n + 6)
            if ratio > 0.75 and m % 4 == 0:
                complexity *= (1.08 + 0.03 * m)
            elif ratio < 0.15 and m % 5 == 0:
                complexity *= (0.88 - 0.02 * m)
            if m % 6 == 1 and cap % (m + 2) == 0:
                penalty += np.cos(m * ratio * 3) * 0.4
            if cap % (m + 1) == 0:
                mod_factor *= 1.03
            else:
                mod_factor *= 0.97
        base_score += penalty * 0.7
        adjusted_score = base_score * complexity * mod_factor
        if adjusted_score <= 0:
            priorities[idx] = -adjusted_score * np.log1p(cap + item*2) / (np.sqrt(cap + 1))
        else:
            if cap > 2 * item:
                priorities[idx] = -adjusted_score / (np.log1p(cap)) * (1 + ratio**1.5)
            else:
                priorities[idx] = -adjusted_score / (cap + 5) * np.exp(-ratio * 2)
        if ratio > 1:
            priorities[idx] *= 1.2
        elif ratio < 0.02:
            priorities[idx] *= 0.7
        if cap % 3 == 0:
            priorities[idx] *= 0.95
        elif cap % 5 == 0:
            priorities[idx] *= 1.05
        if ratio > 0.9:
            priorities[idx] *= 1.1
        elif 0.1 < ratio < 0.3:
            priorities[idx] *= 0.85
    return priorities
